import React from "react";
import "./CalendarGrid.css";
import events from "../data/events";

const CalendarGrid = ({ currentDate, view, today }) => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const startOfMonth = new Date(year, month, 1);
  const endOfMonth = new Date(year, month + 1, 0);

  const startDay = startOfMonth.getDay();
  const totalDays = endOfMonth.getDate();

  const days = [];

  // Empty cells before first day
  for (let i = 0; i < startDay; i++) {
    days.push(null);
  }

  // Month days
  for (let d = 1; d <= totalDays; d++) {
    days.push(new Date(year, month, d));
  }

  // WEEK VIEW FILTER
  let displayDays = days;
  if (view === "week") {
    const todayIndex = days.findIndex(
      (d) => d && d.toDateString() === today.toDateString()
    );
    const start = Math.floor(todayIndex / 7) * 7;
    displayDays = days.slice(start, start + 7);
  }

  return (
    <div className="calendar-grid">
      {displayDays.map((date, index) => {
        const isToday =
          date && date.toDateString() === today.toDateString();

        return (
          <div
            key={index}
            className={`day-cell ${isToday ? "today" : ""}`}
          >
            {date && <span className="date-number">{date.getDate()}</span>}

            {date &&
              events
                .filter(
                  (e) =>
                    e.day === date.getDate()
                )
                .map((e, i) => (
                  <div key={i} className={`event ${e.type}`}>
                    {e.title}
                  </div>
                ))}
          </div>
        );
      })}
    </div>
  );
};

export default CalendarGrid;
